CREATE TABLE t_p79710325_user_profile_dashboa.work_orders (id SERIAL PRIMARY KEY, number VARCHAR(20) UNIQUE NOT NULL, post_id INTEGER REFERENCES t_p79710325_user_profile_dashboa.posts(id), client_name VARCHAR(150), client_phone VARCHAR(30), car_model VARCHAR(150), car_plate VARCHAR(30), description TEXT, start_time TIMESTAMPTZ NOT NULL, duration_hours NUMERIC(4,1) NOT NULL DEFAULT 1, end_time TIMESTAMPTZ, status VARCHAR(20) DEFAULT 'pending', created_by INTEGER REFERENCES t_p79710325_user_profile_dashboa.users(id), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())
